export function getCurrentLanguage() {
    return currentLanguage;
}

export function t(key) {
    const active = TRANSLATIONS[currentLanguage] || TRANSLATIONS[DEFAULT_LANGUAGE];
    const fallback = TRANSLATIONS[DEFAULT_LANGUAGE];
    return active[key] || fallback[key] || key;
}

export async function initializeLanguage() {
    let language = resolvePreferredLanguage();
    try {
        const payload = await fetchUiLanguageSettings();
        if (isSupportedLanguage(payload?.language)) {
            language = payload.language;
        }
    } catch (_) {
        // Fall back to local preference when the backend is unavailable.
    }
    applyLanguage(language);
}

export async function toggleLanguage() {
    const nextLanguage = currentLanguage === 'zh-CN' ? 'en-US' : 'zh-CN';
    applyLanguage(nextLanguage);
    try {
        await saveUiLanguageSettings({ language: nextLanguage });
    } catch (_) {
        // Keep the local language even if persistence fails.
    }
}

export function translateDocument(root = document) {
    if (!root?.querySelectorAll) {
        return;
    }
    root.querySelectorAll('[data-i18n]').forEach(element => {
        element.textContent = t(element.dataset.i18n);
    });
    root.querySelectorAll('[data-i18n-title]').forEach(element => {
        element.setAttribute('title', t(element.dataset.i18nTitle));
    });
    root.querySelectorAll('[data-i18n-placeholder]').forEach(element => {
        element.setAttribute('placeholder', t(element.dataset.i18nPlaceholder));
    });
    root.querySelectorAll('[data-i18n-aria-label]').forEach(element => {
        element.setAttribute('aria-label', t(element.dataset.i18nAriaLabel));
    });
    updateLanguageButton();
}

function applyLanguage(language) {
    currentLanguage = isSupportedLanguage(language) ? language : DEFAULT_LANGUAGE;
    persistLocalLanguage(currentLanguage);
    if (document?.documentElement) {
        document.documentElement.lang = currentLanguage;
    }
    translateDocument(document);
    document.dispatchEvent(
        new CustomEvent('agent-teams-language-changed', {
            detail: { language: currentLanguage },
        }),
    );
}

function resolvePreferredLanguage() {
    const storedLanguage = readStoredLanguage();
    if (isSupportedLanguage(storedLanguage)) {
        return storedLanguage;
    }
    const browserLanguage = typeof navigator?.language === 'string' ? navigator.language : '';
    if (browserLanguage.toLowerCase().startsWith('zh')) {
        return 'zh-CN';
    }
    return DEFAULT_LANGUAGE;
}

function updateLanguageButton() {
    const button = document?.getElementById?.('language-toggle-btn');
    if (!button) {
        return;
    }
    button.textContent = currentLanguage === 'zh-CN' ? '中文' : 'EN';
    button.setAttribute('title', t('topbar.language_button_title'));
    button.setAttribute('aria-label', t('topbar.language_button_title'));
}

function readStoredLanguage() {
    try {
        return localStorage.getItem(STORAGE_KEY);
    } catch (_) {
        return null;
    }
}

function persistLocalLanguage(language) {
    try {
        localStorage.setItem(STORAGE_KEY, language);
    } catch (_) {
        // Ignore localStorage failures in restricted runtimes.
    }
}

function isSupportedLanguage(language) {
    return typeof language === 'string' && SUPPORTED_LANGUAGES.has(language);
}
